import React, { useState, useEffect } from 'react';

const defaultCategories = [
  { id: 'btech', label: 'B.Tech', badge: 'DEGREE', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Metallurgical Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering', 'Computer Engineering', 'Cyber Security', 'Information Technology', 'Computer Science Engineering', 'Aircraft Maintenance Engineering', 'Aeronautical Engineering', 'Aerospace Engineering', 'Defence Aerospace Engineering'] },
  { id: 'btech-dtd', label: 'B.Tech (D to D)', badge: 'LATERAL', color: 'border-amber-700', bgColor: 'bg-amber-700', lightBg: 'bg-amber-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Metallurgical Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering', 'Computer Engineering', 'Cyber Security', 'Information Technology', 'Computer Science Engineering'] },
  { id: 'diploma', label: 'Diploma', badge: 'TECHNICAL', color: 'border-orange-500', bgColor: 'bg-orange-500', lightBg: 'bg-orange-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Computer Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering'] },
  { id: 'mtech', label: 'M.Tech', badge: 'MASTERS', color: 'border-red-600', bgColor: 'bg-red-600', lightBg: 'bg-red-50', programs: ['CAD / CAM (Mechanical Engr.)', 'Construction Project Management (Civil Engg.)', 'Digital Communication (EC Engg.)', 'Electrical Power System', 'Industrial Metallurgy', 'Structural Engineering (Civil Engg.)', 'Data Science (Computer)', 'Cyber Security'] },
  { id: 'bdes', label: 'B.Des', badge: 'DESIGN', color: 'border-yellow-500', bgColor: 'bg-yellow-500', lightBg: 'bg-yellow-50', programs: ['Product Design', 'Interior Design', 'Fashion Design', 'Communication Design - (Graphic Design)'] },
  { id: 'mdes', label: 'M.Des', badge: 'MASTERS', color: 'border-teal-600', bgColor: 'bg-teal-600', lightBg: 'bg-teal-50', programs: ['Fashion Design', 'Interior Design', 'UI-UX Design'] },
  { id: 'bsc', label: 'B.Sc', badge: 'SCIENCE', color: 'border-blue-400', bgColor: 'bg-blue-400', lightBg: 'bg-blue-50', programs: ['Data Science', 'Computer Application (CA) & (IT)', 'Clinical Research (Hons)', 'Mathematics (Hons)', 'Physics (Hons)', 'Chemistry (Hons)', 'Cyber Security (Hons)', 'Microbiology (Hons)', 'Computer Science (AI & ML)'] },
  { id: 'msc', label: 'M.Sc', badge: 'MASTERS', color: 'border-indigo-600', bgColor: 'bg-indigo-600', lightBg: 'bg-indigo-50', programs: ['Information Technology (IT)', 'Clinical Research', 'Mathematics', 'Physics', 'Chemistry', 'Cyber Security', 'Microbiology'] },
  { id: 'mba-avia', label: 'MBA/BBA', badge: 'BUSINESS', color: 'border-purple-600', bgColor: 'bg-purple-600', lightBg: 'bg-purple-50', programs: ['Aviation Management', 'BBA', 'Marketing', 'Finance', 'Human Resource'] },
  { id: 'bca', label: 'BCA', badge: 'COMPUTER', color: 'border-cyan-500', bgColor: 'bg-cyan-500', lightBg: 'bg-cyan-50', programs: ['BCA'] },
  { id: 'mca', label: 'MCA', badge: 'POST-GRAD', color: 'border-rose-500', bgColor: 'bg-rose-500', lightBg: 'bg-rose-50', programs: ['MCA'] }
];

export default function AdminCategories({ confirmDelete }) {
  const [categories, setCategories] = useState([]);
  const [catForm, setCatForm] = useState({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });
  const [selectedCategoryNav, setSelectedCategoryNav] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [programData, setProgramData] = useState({});
  const [selectedProgramEdit, setSelectedProgramEdit] = useState('');
  const [jsonInput, setJsonInput] = useState('');
  const [newCourseName, setNewCourseName] = useState('');
  const [activeMetadataTab, setActiveMetadataTab] = useState('CURRICULUM & LEARNING');

  const metadataTabs = [
    { id: 'CURRICULUM & LEARNING', label: 'Curriculum' },
    { id: 'INDUSTRY EXPOSURE', label: 'Industry' },
    { id: 'CAREER PROSPECTS', label: 'Career' },
    { id: 'WHY CHOOSE US', label: 'Choice' },
    { id: 'ELIGIBILITY', label: 'Eligibility' },
    { id: 'ADMISSION', label: 'Admission' },
    { id: 'FEES STRUCTURE', label: 'Fees' }
  ];

  useEffect(() => {
    const loadCategories = () => {
      const storedCat = localStorage.getItem('indus_categories');
      setCategories(storedCat ? JSON.parse(storedCat) : defaultCategories);
    };
    loadCategories();
    const storedProg = localStorage.getItem('indus_programData');
    setProgramData(storedProg ? JSON.parse(storedProg) : {});
  }, []);

  const saveCats = (data) => {
    setCategories(data);
    localStorage.setItem('indus_categories', JSON.stringify(data));
  };

  const saveProgData = (data) => {
    setProgramData(data);
    localStorage.setItem('indus_programData', JSON.stringify(data));
  };

  const handleProgramSelect = (prog) => {
    setSelectedProgramEdit(prog);
    const data = programData[prog] || { 'CURRICULUM & LEARNING': { sections: [{ title: 'Overview', items: ['Point 1'] }] } };
    setJsonInput(JSON.stringify(data, null, 2));
  };

  const handleJsonSave = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      saveProgData({ ...programData, [selectedProgramEdit]: parsed });
      alert('Program details updated successfully!');
      setSelectedProgramEdit('');
    } catch(err) {
      alert('Invalid JSON format: ' + err.message);
    }
  };

  const updateMethodology = (newContent) => setJsonInput(JSON.stringify(newContent, null, 2));

  if (selectedProgramEdit) {
    const allData = JSON.parse(jsonInput);
    const activeData = allData[activeMetadataTab] || { sections: [] };

    return (
      <div className="space-y-8 fade-in max-w-7xl mx-auto pb-16 px-8">
        {/* Header Block */}
        <div className="bg-white border border-slate-200 p-8 rounded-2xl shadow-sm flex items-center justify-between">
           <div className="flex items-center gap-6">
              <button onClick={() => setSelectedProgramEdit('')} className="p-4 bg-slate-50 border border-slate-200 rounded-xl text-slate-400 hover:text-slate-900 transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <div>
                 <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em] mb-1">Editor Console</p>
                 <h1 className="text-4xl font-black text-slate-900 tracking-tight">{selectedProgramEdit}</h1>
              </div>
           </div>
           <button onClick={handleJsonSave} className="bg-slate-900 text-white font-black px-10 py-4 rounded-xl hover:bg-black shadow-lg shadow-slate-900/10 hover:shadow-xl transition-all uppercase tracking-widest text-xs">Save Changes</button>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 items-start">
           {/* Navigation Sidebar */}
           <div className="lg:w-64 sticky top-10 flex flex-col gap-2 bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
                <span className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] mb-3 px-4 block">Categories</span>
                {metadataTabs.map(tab => (
                   <button 
                     key={tab.id}
                     onClick={() => setActiveMetadataTab(tab.id)}
                     className={`w-full text-left px-5 py-4 rounded-xl text-sm font-bold uppercase tracking-wider transition-all ${
                       activeMetadataTab === tab.id 
                       ? 'bg-slate-900 text-white shadow-lg shadow-slate-900/20 scale-[1.02]' 
                       : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'
                     }`}
                   >
                     {tab.label}
                   </button>
                ))}
           </div>

           {/* Content Canvas */}
           <div className="flex-1 space-y-8 bg-[#f8f7f5] p-10 rounded-3xl border border-slate-200/60 shadow-inner">
              <div className="flex items-center gap-4 mb-8">
                 <div className="h-px flex-1 bg-slate-200"></div>
                 <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] bg-white px-6 py-2.5 rounded-full border border-slate-200">Managing: {activeMetadataTab}</span>
                 <div className="h-px flex-1 bg-slate-200"></div>
              </div>

              {activeData.sections && activeData.sections.map((section, sIdx) => (
                <div key={sIdx} className="bg-white p-10 rounded-2xl shadow-sm border border-slate-200 relative group hover:shadow-md transition-all">
                   <button 
                     onClick={() => {
                       const updated = JSON.parse(jsonInput);
                       updated[activeMetadataTab].sections.splice(sIdx, 1);
                       updateMethodology(updated);
                     }}
                     className="absolute top-8 right-8 text-slate-200 hover:text-red-500 transition-colors"
                   >
                     <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                   </button>

                   <div className="mb-10">
                      <label className="block text-[11px] font-black text-blue-500 uppercase tracking-[0.2em] mb-4">Section Header</label>
                      <input 
                        type="text" 
                        value={section.title}
                        onChange={(e) => {
                          const updated = JSON.parse(jsonInput);
                          updated[activeMetadataTab].sections[sIdx].title = e.target.value;
                          updateMethodology(updated);
                        }}
                        className="w-full text-4xl font-black text-slate-900 border-none outline-none focus:ring-0 p-0 placeholder-slate-200"
                        placeholder="e.g. Program Overview"
                      />
                   </div>

                   <div className="space-y-6">
                      <label className="block text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Core Information Points</label>
                       {section.items.map((item, pIdx) => (
                        <div key={pIdx} className="flex gap-4 items-center group/p">
                           <input 
                             type="text" 
                             value={item}
                             onChange={(e) => {
                               const updated = JSON.parse(jsonInput);
                               updated[activeMetadataTab].sections[sIdx].items[pIdx] = e.target.value;
                               updateMethodology(updated);
                             }}
                             className="flex-1 bg-slate-50 border border-slate-100 focus:border-slate-400 px-8 py-6 rounded-2xl font-bold text-slate-800 outline-none focus:bg-white text-lg leading-relaxed shadow-sm"
                           />
                           <button 
                             onClick={() => {
                               const updated = JSON.parse(jsonInput);
                               updated[activeMetadataTab].sections[sIdx].items.splice(pIdx, 1);
                               updateMethodology(updated);
                             }}
                             className="w-12 h-12 bg-red-50 text-red-300 hover:text-white hover:bg-red-500 transition-all rounded-xl flex items-center justify-center shrink-0 opacity-0 group-hover/p:opacity-100"
                           >
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
                           </button>
                        </div>
                      ))}
                      <button 
                        onClick={() => {
                          const updated = JSON.parse(jsonInput);
                          updated[activeMetadataTab].sections[sIdx].items.push("New Info Point");
                          updateMethodology(updated);
                        }}
                        className="mt-4 px-6 py-3 bg-blue-50 text-blue-600 font-black text-xs uppercase tracking-widest rounded-xl hover:bg-blue-600 hover:text-white transition-all border border-blue-100"
                      >
                        + Add Point
                      </button>
                   </div>
                </div>
              ))}

              <button 
                onClick={() => {
                  const updated = JSON.parse(jsonInput);
                  if (!updated[activeMetadataTab]) updated[activeMetadataTab] = { sections: [] };
                  updated[activeMetadataTab].sections.push({ title: 'New Section', items: ['Info point here'] });
                  updateMethodology(updated);
                }}
                className="w-full border-2 border-dashed border-slate-300 p-12 rounded-3xl text-slate-400 font-bold hover:border-slate-900 hover:text-slate-900 hover:bg-white transition-all text-sm uppercase tracking-widest flex items-center justify-center gap-4 group"
              >
                <div className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center group-hover:bg-slate-900 group-hover:text-white transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4" /></svg></div>
                Append New Metadata Section
              </button>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-16 fade-in max-w-7xl mx-auto pb-24 px-8">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">
        {/* Creator Sidebar */}
        <div className="lg:col-span-4 sticky top-10">
           <div className="bg-white border border-slate-200 p-10 rounded-3xl shadow-sm relative overflow-hidden">
             <div className="absolute top-0 right-0 w-32 h-32 bg-slate-50 rotate-45 translate-x-16 -translate-y-16"></div>
             <h2 className="text-3xl font-black mb-8 text-slate-900 tracking-tight leading-none relative z-10">{catForm.id ? 'Refine Track' : 'New Academic Track'}</h2>
             <form onSubmit={saveCategory} className="space-y-6 relative z-10">
                <div className="space-y-4">
                   <label className="block text-[11px] font-black uppercase text-slate-400 tracking-widest pl-1">Display Label</label>
                   <input required type="text" value={catForm.label} onChange={e => setCatForm({...catForm, label: e.target.value})} className="w-full bg-slate-50 border border-slate-200 px-6 py-5 rounded-2xl outline-none font-bold text-lg focus:border-slate-900 focus:bg-white transition-all shadow-sm" placeholder="e.g. B.Tech" />
                </div>
                <div className="space-y-4">
                   <label className="block text-[11px] font-black uppercase text-slate-400 tracking-widest pl-1">Category Badge</label>
                   <input required type="text" value={catForm.badge} onChange={e => setCatForm({...catForm, badge: e.target.value})} className="w-full bg-slate-50 border border-slate-200 px-6 py-5 rounded-2xl outline-none font-bold uppercase text-lg focus:border-slate-900 focus:bg-white transition-all shadow-sm" placeholder="e.g. Degree" />
                </div>
                <div className="space-y-4">
                   <label className="block text-[11px] font-black uppercase text-slate-400 tracking-widest pl-1">Program Listing</label>
                   <textarea placeholder="Civil, Mechanical, Automobile..." value={typeof catForm.programs === 'string' ? catForm.programs : catForm.programs.join(', ')} onChange={e => setCatForm({...catForm, programs: e.target.value})} className="w-full bg-slate-50 border border-slate-200 px-6 py-5 rounded-2xl outline-none font-bold text-lg min-h-[160px] focus:border-slate-900 focus:bg-white transition-all leading-relaxed shadow-sm"></textarea>
                </div>
                <div className="flex gap-4 pt-4">
                   <button type="submit" className="flex-1 bg-slate-900 text-white font-black py-5 rounded-2xl hover:bg-black shadow-lg shadow-slate-900/10 hover:shadow-xl transition-all uppercase tracking-widest text-xs">Authorize Track</button>
                   {catForm.id && <button type="button" onClick={() => setCatForm({ id: '', label: '', badge: '', programs: '' })} className="px-6 bg-slate-100 border border-slate-200 rounded-2xl font-black text-slate-500 hover:bg-slate-200 transition-all text-xs uppercase tracking-widest text-xs">Esc</button>}
                </div>
             </form>
           </div>
        </div>

        {/* Global Tracks Directory */}
        <div className="lg:col-span-8 space-y-12 bg-white/40 p-10 rounded-3xl border border-slate-200/50 shadow-inner">
           <div className="flex items-center justify-between">
              <h3 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-4">
                System Registry 
                <span className="text-xs font-black px-4 py-1.5 bg-slate-900 text-white rounded-full tracking-widest uppercase">{categories.length}</span>
              </h3>
           </div>

           <div className="flex flex-col gap-5 max-h-[80vh] overflow-y-auto pr-4 custom-scrollbar px-1">
              {categories.map((cat) => (
                <div key={cat.id} className="bg-white p-8 rounded-3xl border border-slate-200 flex flex-col md:flex-row items-center justify-between hover:shadow-2xl hover:shadow-slate-200 hover:-translate-y-1 transition-all duration-300 group gap-8">
                   <div className="flex-1 flex flex-col md:flex-row md:items-center gap-8">
                      <div className="shrink-0">
                         <div className="text-[10px] font-black text-slate-300 tracking-[0.2em] uppercase mb-1">{cat.badge} • CAT</div>
                         <h4 className="text-3xl font-black text-slate-900 tracking-tighter leading-none">{cat.label}</h4>
                      </div>
                      <div className="h-10 w-px bg-slate-100 hidden md:block"></div>
                      <div className="flex items-center gap-3 text-sm font-bold text-slate-400">
                        <div className="w-2 h-2 rounded-full bg-slate-900"></div>
                        {cat.programs.length} Specialized Academic Programs
                      </div>
                   </div>

                   <div className="flex items-center gap-4 shrink-0">
                      <button 
                        onClick={() => setSelectedCategoryNav(cat)} 
                        className="px-10 py-4 bg-slate-900 text-white text-[11px] font-black rounded-2xl hover:bg-blue-600 shadow-lg shadow-slate-900/10 transition-all uppercase tracking-widest"
                      >
                        Launch Management
                      </button>
                      <button 
                        onClick={() => setCatForm(cat)} 
                        className="w-14 h-14 bg-slate-50 border border-slate-100 text-slate-300 rounded-2xl flex items-center justify-center hover:text-slate-900 hover:bg-slate-100 transition-all"
                      >
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                      </button>
                      <button 
                        onClick={() => confirmDelete('category', cat.id, cat.label)} 
                        className="w-14 h-14 bg-white border border-red-50 text-red-100 rounded-2xl flex items-center justify-center hover:text-white hover:bg-red-500 hover:border-red-500 transition-all shadow-sm"
                      >
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                   </div>
                </div>
              ))}
           </div>
        </div>
      </div>
    </div>
  );
}
